import{_ as o,o as d,c,ai as a}from"./chunks/framework.CsYGeNYI.js";const p=JSON.parse('{"title":"Bridge 协议","description":"","frontmatter":{"read_when":["构建或调试节点客户端（iOS/Android/macOS 节点模式）","调查配对或 bridge 认证失败","审计 Gateway 网关暴露的节点接口"],"summary":"Bridge 协议（旧版节点）：TCP JSONL、配对、作用域 RPC","title":"Bridge 协议","x-i18n":{"generated_at":"2026-02-03T07:47:42Z","model":"claude-opus-4-5","provider":"pi","source_hash":"789bcf3cbc6841fc293e054b919e63d661b3cc4cd205b2094289f00800127fe2","source_path":"gateway/bridge-protocol.md","workflow":15}},"headers":[],"relativePath":"zh-CN/gateway/bridge-protocol.md","filePath":"zh-CN/gateway/bridge-protocol.md","lastUpdated":1771906665000}'),i={name:"zh-CN/gateway/bridge-protocol.md"};function r(t,e,l,s,n,h){return d(),c("div",null,[...e[0]||(e[0]=[a('<h1 id="bridge-协议-旧版节点传输" tabindex="-1"><a class="header-anchor" href="#bridge-协议-旧版节点传输">#</a> Bridge 协议（旧版节点传输）</h1><p>Bridge 协议是一个<strong>旧版</strong>节点传输（TCP JSONL）。新的节点客户端应该使用统一的 Gateway 网关 WebSocket 协议。</p><p>如果你正在构建操作者或节点客户端，请使用 <a href="/docs/gateway/protocol">Gateway 网关协议</a>。</p><p><strong>注意：</strong> 当前的 OpenSoul 构建不再包含 TCP bridge 监听器；本文档仅作历史参考保留。 旧版 <code>bridge.*</code> 配置键不再是配置模式的一部分。</p><h2 id="为什么我们有两种协议" tabindex="-1"><a class="header-anchor" href="#为什么我们有两种协议">#</a> 为什么我们有两种协议</h2><ul><li><strong>安全边界</strong>：bridge 暴露一个小的允许列表，而不是完整的 Gateway 网关 API 接口。</li><li><strong>配对 + 节点身份</strong>：节点准入由 Gateway 网关管理，并与每节点令牌绑定。</li><li><strong>设备发现用户体验</strong>：节点可以通过局域网上的 Bonjour 发现 Gateway 网关，或通过 tailnet 直接连接。</li><li><strong>Loopback WS</strong>：完整的 WS 控制平面保持本地，除非通过 SSH 隧道。</li></ul><h2 id="传输" tabindex="-1"><a class="header-anchor" href="#传输">#</a> 传输</h2><ul><li>TCP，每行一个 JSON 对象（JSONL）。</li><li>可选 TLS（当 <code>bridge.tls.enabled</code> 为 true 时）。</li><li>旧版默认监听端口为 <code>18790</code>（当前构建不启动 TCP bridge）。</li></ul><p>当 TLS 启用时，设备发现 TXT 记录包含 <code>bridgeTls=1</code> 加上 <code>bridgeTlsSha256</code>，以便节点可以固定证书。</p><h2 id="握手-配对" tabindex="-1"><a class="header-anchor" href="#握手-配对">#</a> 握手 + 配对</h2><ol><li>客户端发送带有节点元数据 + 令牌（如果已配对）的 <code>hello</code>。</li><li>如果未配对，Gateway 网关回复 <code>error</code>（<code>NOT_PAIRED</code>/<code>UNAUTHORIZED</code>）。</li><li>客户端发送 <code>pair-request</code>。</li><li>Gateway 网关等待批准，然后发送 <code>pair-ok</code> 和 <code>hello-ok</code>。</li></ol><p><code>hello-ok</code> 返回 <code>serverName</code>，可能包含 <code>canvasHostUrl</code>。</p><h2 id="帧" tabindex="-1"><a class="header-anchor" href="#帧">#</a> 帧</h2><p>客户端 → Gateway 网关：</p><ul><li><code>req</code> / <code>res</code>：作用域 Gateway 网关 RPC（chat、sessions、config、health、voicewake、skills.bins）</li><li><code>event</code>：节点信号（语音转录、智能体请求、聊天订阅、exec 生命周期）</li></ul><p>Gateway 网关 → 客户端：</p><ul><li><code>invoke</code> / <code>invoke-res</code>：节点命令（<code>canvas.*</code>、<code>camera.*</code>、<code>screen.record</code>、<code>location.get</code>、<code>sms.send</code>）</li><li><code>event</code>：已订阅会话的聊天更新</li><li><code>ping</code> / <code>pong</code>：保活</li></ul><p>旧版允许列表强制执行位于 <code>src/gateway/server-bridge.ts</code>（已移除）。</p><h2 id="exec-生命周期事件" tabindex="-1"><a class="header-anchor" href="#exec-生命周期事件">#</a> Exec 生命周期事件</h2><p>节点可以发出 <code>exec.finished</code> 或 <code>exec.denied</code> 事件来表面化 system.run 活动。 这些被映射到 Gateway 网关中的系统事件。（旧版节点可能仍会发出 <code>exec.started</code>。）</p><p>Payload 字段（除非注明，否则都是可选的）：</p><ul><li><code>sessionKey</code>（必需）：接收系统事件的智能体会话。</li><li><code>runId</code>：用于分组的唯一 exec id。</li><li><code>command</code>：原始或格式化的命令字符串。</li><li><code>exitCode</code>、<code>timedOut</code>、<code>success</code>、<code>output</code>：完成详情（仅限 finished）。</li><li><code>reason</code>：拒绝原因（仅限 denied）。</li></ul><h2 id="tailnet-使用" tabindex="-1"><a class="header-anchor" href="#tailnet-使用">#</a> Tailnet 使用</h2><ul><li>将 bridge 绑定到 tailnet IP：在 <code>~/.opensoul/opensoul.json</code> 中设置 <code>bridge.bind: &quot;tailnet&quot;</code>。</li><li>客户端通过 MagicDNS 名称或 tailnet IP 连接。</li><li>Bonjour <strong>不</strong>跨网络；需要时使用手动主机/端口或广域 DNS‑SD。</li></ul><h2 id="版本控制" tabindex="-1"><a class="header-anchor" href="#版本控制">#</a> 版本控制</h2><p>Bridge 目前是<strong>隐式 v1</strong>（无最小/最大协商）。预期向后兼容；在任何破坏性变更之前添加 bridge 协议版本字段。</p>',26)])])}const b=o(i,[["render",r]]);export{p as __pageData,b as default};
